    uint32_t totalLength = M * N;

    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    const float *scaling = attrs->GetAttrPointer<float>(0);

    // Determine tile sizes: conservative UB estimate
    uint32_t tileM = 128;
    uint32_t tileN = 128;
    uint32_t tileK = 256;

    // Clamp to matrix dimensions
    if (tileM > M) tileM = AlignDown(M, ALIGN_ELEMS);
    if (tileN > N) tileN = AlignDown(N, ALIGN_ELEMS);

    uint32_t blockDim = CeilDiv(M, tileM) * CeilDiv(N, tileN);
    if (blockDim < 8) blockDim = 8;
    if (blockDim > 24) blockDim = 24;

    context->SetBlockDim(blockDim);

    tiling.set_M(M);
    tiling.set_N(N);
    tiling.set_K(K);
    tiling.set_tileM(tileM);
    tiling.set_tileN(tileN);
    tiling.set_tileK(tileK);
    tiling.set_totalLength(totalLength);
    tiling.set_blockDim(blockDim);
    tiling.set_scaling(*scaling);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(), context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *workspace = context->GetWorkspaceSizes(1);
    workspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

